public Vector<String> getNetworkServersIPs(String netaddress) {
    Vector<String> result = new Vector<String>();
    boolean serverline = false;
    String line;
    String[] splitline;
    try {
        URL url = new URL(netaddress);
        URLConnection connection = url.openConnection();
        BufferedReader reader = new BufferedReader(new InputStreamReader(connection.getInputStream()));
        while ((line = reader.readLine()) != null) {
            if ((serverline) && line.startsWith(";")) {
                serverline = false;
            }
            if (serverline) {
                splitline = line.split(":");
                result.add(splitline[1]);
            }
            if (line.startsWith("!SERVERS")) {
                serverline = true;
            }
        }
    } catch (MalformedURLException e) {
        e.printStackTrace();
    } catch (IOException e) {
        e.printStackTrace();
    }
    return result;
}
protected void readURL(URL url) {
    InputStream istream = null;
    InputStreamReader isr = null;
    BufferedReader in = null;
    try {
        istream = url.openStream();
        isr = new InputStreamReader(istream);
        in = new BufferedReader(isr);
        String line = in.readLine();
        while (null != line) {
            System.out.println(line);
            line = in.readLine();
        }
    } catch (Exception e) {
        e.printStackTrace();
    } finally {
        IOUtilities.close(in);
        IOUtilities.close(isr);
        IOUtilities.close(istream);
    }
}

