private static void copyFile(String src, String target) throws IOException {
    FileChannel ic = new FileInputStream(src).getChannel();
    FileChannel oc = new FileOutputStream(target).getChannel();
    ic.transferTo(0, ic.size(), oc);
    ic.close();
    oc.close();
}
public static void copyFile(File src, File dest, int bufSize, boolean force) throws IOException {
    logger.info("copyFile(File src=" + src + ", File dest=" + dest + ", int bufSize=" + bufSize + ", boolean force=" + force + ") - start");
    File f = new File(Configuration.getArchiveDir());
    if (!f.exists()) {
        f.mkdir();
    }
    if (dest.exists()) {
        if (force) {
            dest.delete();
        } else {
            throw new IOException("Cannot overwrite existing file: " + dest);
        }
    }
    byte[] buffer = new byte[bufSize];
    int read = 0;
    InputStream in = null;
    OutputStream out = null;
    try {
        in = new FileInputStream(src);
        out = new FileOutputStream(dest);
        while (true) {
            read = in.read(buffer);
            if (read == -1) {
                break;
            }
            out.write(buffer, 0, read);
        }
    } finally {
        if (in != null) {
            try {
                in.close();
            } finally {
                if (out != null) {
                    out.close();
                }
            }
        }
    }
    logger.debug("copyFile(File, File, int, boolean) - end");
}

