                if ((c - 1) == size && size != 0) {
                    System.out.print("#");
                    c = 1;
                    written++;
                } else if (size == 0) {
                    int j = 1;
                    if (c > 1) j = (50 / c) - 50; else j = 50 / c;
                    for (int i = 0; i < j; i++) System.out.print("#");
                    written += j;
                }
            }
            bytes_read = source.read(buffer);
            if (bytes_read == -1) break;
            destination.write(buffer, 0, bytes_read);
            c++;
        }
        System.out.println();
    } finally {
        if (source != null) try {
            source.close();
        } catch (IOException e) {
        }
        if (destination != null) try {
            destination.close();
        } catch (IOException e) {
        }
    }
}

