public static void copyFile(File src, File dest, int bufSize, boolean force) throws IOException {
    if (dest.exists()) if (force) dest.delete(); else throw new IOException("Cannot overwrite existing file: " + dest.getName());
    byte[] buffer = new byte[bufSize];
    int read = 0;
    InputStream in = null;
    OutputStream out = null;
    try {
        in = new FileInputStream(src);
        out = new FileOutputStream(dest);
        while (true) {
            read = in.read(buffer);
            if (read == -1) break;
            out.write(buffer, 0, read);
        }
    } finally {
        if (in != null) try {
            in.close();
        } finally {
            if (out != null) out.close();
        }
    }
}
public static void copyFileChannel(File src, File dst, boolean preserveModificationTime) throws IOException {
    FileChannel inputChannel = null;
    FileChannel outputChannel = null;
    long length = 0;
    try {
        inputChannel = new FileInputStream(src).getChannel();
        length = inputChannel.size();
        outputChannel = new FileOutputStream(dst).getChannel();
        long total = 0;
        while (total < length) {
            total += inputChannel.transferTo(0, length, outputChannel);
        }
        if (preserveModificationTime) {
            dst.setLastModified(src.lastModified());
        }
    } finally {
        if (inputChannel != null) {
            inputChannel.close();
        }
        if (outputChannel != null) {
            outputChannel.close();
        }
    }
}

