                throw new ModelGenerationException("Sorry, i failed to use this template: " + tpl + ". It broke when generating " + outFileName, e);
            } finally {
                IOUtils.closeQuietly(in);
            }
            break;
        case copy:
            try {
                in = new FileInputStream(tpl.getAbsolutePath());
