public static String hash(String text) throws NoSuchAlgorithmException, UnsupportedEncodingException {
    MessageDigest md = MessageDigest.getInstance("SHA-1");
    byte[] sha1hash = new byte[40];
    md.update(text.getBytes("iso-8859-1"), 0, text.length());
    sha1hash = md.digest();
    return SHA1.convertToHex(sha1hash);
}
public static String encrypt(String text) {
    char[] toEncrypt = text.toCharArray();
    StringBuffer hexString = new StringBuffer();
    try {
        MessageDigest dig = MessageDigest.getInstance("MD5");
        dig.reset();
        String pw = "";
        for (int i = 0; i < toEncrypt.length; i++) {
            pw += toEncrypt[i];
        }
        dig.update(pw.getBytes());
        byte[] digest = dig.digest();
        int digestLength = digest.length;
        for (int i = 0; i < digestLength; i++) {
            hexString.append(hexDigit(digest[i]));
        }
    } catch (java.security.NoSuchAlgorithmException ae) {
        ae.printStackTrace();
    }
    return hexString.toString();
}

