                    contextXml = parseXml(source);
                }
            } finally {
                source.close();
            }
        }
        if (webXml == null) {
            throw new IllegalArgumentException("WEB-INF/web.xml not found");
        }
        if (portletXml == null) {
            throw new IllegalArgumentException("WEB-INF/portlet.xml not found");
