        System.out.println("War " + outputName + " created");
        System.out.flush();
    } finally {
        if (srcChannel != null && srcChannel.isOpen()) {
            try {
                srcChannel.close();
            } catch (IOException e1) {
            }
        }
        if (dstChannel != null && dstChannel.isOpen()) {
            try {
                dstChannel.close();
            } catch (IOException e1) {
            }
        }
        if (jin != null) {
            try {
                jin.close();
                jin = null;
            } catch (IOException e1) {
            }
        }
        if (jout != null) {
            try {
                jout.close();
                jout = null;
            } catch (IOException e1) {
            }
        }
        if (tempFile != null && tempFile.exists()) {
            tempFile.delete();
        }
    }
}

